--
-- Table structure for table `patient`
--

DROP TABLE IF EXISTS `patient`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `patient` (
  `ID` int NOT NULL,
  `LAST_FREG_DATE` date DEFAULT NULL,
  `REGISTERED_DATE` date DEFAULT NULL,
  `SSN` varchar(100) DEFAULT NULL,
  `SSN_TYPE` tinyint DEFAULT NULL,
  `SSNSUBTYPE` tinyint DEFAULT NULL,
  `LASTNAME` varchar(200) DEFAULT NULL,
  `FIRSTNAME` varchar(200) DEFAULT NULL,
  `BIRTH_DATE` date DEFAULT NULL,
  `NORWEGIAN` tinyint DEFAULT NULL,
  `GENDER` tinyint DEFAULT NULL,
  `MARITAL_STATUS` tinyint DEFAULT NULL,
  `EDUCATION` tinyint DEFAULT NULL,
  `PVK_LISTED` tinyint DEFAULT NULL,
  `DECEASED` tinyint DEFAULT NULL,
  `DECEASED_DATE` date DEFAULT NULL,
  `REAPER_DATE` date DEFAULT NULL,
  `ADDR_TYPE` tinyint DEFAULT NULL,
  `ADDRESS` varchar(200) DEFAULT NULL,
  `DISTRICTCODE` varchar(100) DEFAULT NULL,
  `DISTRICTNAME` varchar(50) DEFAULT NULL,
  `ZIPCODE` varchar(100) DEFAULT NULL,
  `TOWN` varchar(100) DEFAULT NULL,
  `COUNTY` varchar(50) DEFAULT NULL,
  `FREEFORM_ADDR` varchar(500) DEFAULT NULL,
  `PHONE` varchar(100) DEFAULT NULL,
  `ALT_PHONE` varchar(100) DEFAULT NULL,
  `EMAIL` varchar(150) DEFAULT NULL,
  `USERCOMMENT` varchar(2000) DEFAULT NULL,
  `OWNING_CENTRE` varchar(30) DEFAULT NULL,
  `TSUPDATED` timestamp NULL DEFAULT NULL,
  `UPDATEDBY` varchar(255) DEFAULT NULL,
  `FIRST_TIME_CLOSED` timestamp NULL DEFAULT NULL,
  `FIRST_TIME_CLOSED_BY` varchar(255) DEFAULT NULL,
  `TSCREATED` timestamp NULL DEFAULT NULL,
  `CREATEDBY` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`ID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
