DROP TABLE IF EXISTS `surgeonform`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `surgeonform` (
  `MCEID` int NOT NULL,
  `CENTREID` varchar(30) DEFAULT NULL,
  `ADMISSION_DATE` date DEFAULT NULL,
  `SURGERY_DATE` date DEFAULT NULL,
  `HEIGHT` smallint DEFAULT NULL,
  `WEIGHT` smallint DEFAULT NULL,
  `BMI` decimal(4,1) DEFAULT NULL,
  `BMI_CATEGORY` varchar(30) DEFAULT NULL,
  `DOCTOR_INITIAL` varchar(5) DEFAULT NULL,
  `CURRENT_SURGERY` tinyint DEFAULT NULL,
  `REOPERATION_BLEEDING` tinyint DEFAULT NULL,
  `REOPERATION_IMPLANT_BREAKAGE` tinyint DEFAULT NULL,
  `REOPERATION_MISPLACED_IMPLANT` tinyint DEFAULT NULL,
  `REOPERATION_LOOSE_UP_IMPLANT` tinyint DEFAULT NULL,
  `REOPERATION_INFECTION` tinyint DEFAULT NULL,
  `REOPERATION_PAIN` tinyint DEFAULT NULL,
  `REOPERATION_SAGITTAL` tinyint DEFAULT NULL,
  `REOPERATION_CORONAL` tinyint DEFAULT NULL,
  `REOPERATION_NEUROLOGICAL_INJURY` tinyint DEFAULT NULL,
  `REOPERATION_OTHER_DISEASE` tinyint DEFAULT NULL,
  `EARLIER_FIXATION_NONE` tinyint DEFAULT NULL,
  `EARLIER_FIXATION_REAR` tinyint DEFAULT NULL,
  `EARLIER_FIXATION_ANTERIOR` tinyint DEFAULT NULL,
  `EARLIER_FIXATION_VEPTR` tinyint DEFAULT NULL,
  `EARLIER_FIXATION_GROWTH_ROD` tinyint DEFAULT NULL,
  `EARLIER_FIXATION_MAGNETIC_GROWTH_ROD` tinyint DEFAULT NULL,
  `EARLIER_FIXATION_HALO` tinyint DEFAULT NULL,
  `EARLIER_FIXATION_OTHER` tinyint DEFAULT NULL,
  `EARLIER_TREATMENT_NONE` tinyint DEFAULT NULL,
  `EARLIER_TREATMENT_FULL_CORSET` tinyint DEFAULT NULL,
  `EARLIER_TREATMENT_FULL_CORSET_TIME` tinyint DEFAULT NULL,
  `EARLIER_TREATMENT_CORSET_NIGHT` tinyint DEFAULT NULL,
  `EARLIER_TREATMENT_CORSET_TIME` tinyint DEFAULT NULL,
  `DIAGNOSIS` tinyint DEFAULT NULL,
  `CLINICAL_EXAMINATION` tinyint DEFAULT NULL,
  `SHOULDER_SYMMETRY_DIFF` tinyint DEFAULT NULL,
  `GIBBUS` tinyint DEFAULT NULL,
  `PRE_MAIN_CURVE` smallint DEFAULT NULL,
  `MAIN_APEX_LEVEL` tinyint DEFAULT NULL,
  `SECONDARY_CURVE` smallint DEFAULT NULL,
  `SEC_APEX_LEVEL` tinyint DEFAULT NULL,
  `CURVE_TYPE` tinyint DEFAULT NULL,
  `LUMBAR_MODIFIER` tinyint DEFAULT NULL,
  `KYPHOSIS` tinyint DEFAULT NULL,
  `CORONAL_BALANCE_BALANCED` tinyint DEFAULT NULL,
  `CORONAL_BALANCE_RIGHT_RIGHT` tinyint DEFAULT NULL,
  `CORONAL_BALANCE_RIGHT_VALUE` smallint DEFAULT NULL,
  `CORONAL_BALANCE_LEFT` tinyint DEFAULT NULL,
  `CORONAL_BALANCE_LEFT_VALUE` smallint DEFAULT NULL,
  `POST_MAIN_CURVE` smallint DEFAULT NULL,
  `ASA_CLASSIFICATION` tinyint DEFAULT NULL,
  `OPERATION_METHOD` tinyint DEFAULT NULL,
  `OPERATION_METHOD_MUSCLE_SAVING` tinyint DEFAULT NULL,
  `OPERATION_ADD_ON_FIXATION_HOOK` tinyint DEFAULT NULL,
  `OPERATION_ADD_ON_FIXATION_SUBLAMINARY` tinyint DEFAULT NULL,
  `OPERATION_ADD_ON_FIXATION_NONE` tinyint DEFAULT NULL,
  `OPERATION_COMPUTER_NAVIGATION` tinyint DEFAULT NULL,
  `OPERATION_REOPERATION_METHOD_SOFT_PART` tinyint DEFAULT NULL,
  `OPERATION_REOPERATION_METHOD_INSTRUMENT` tinyint DEFAULT NULL,
  `OPERATION_REOPERATION_METHOD_REMOVE_IMPLANT` tinyint DEFAULT NULL,
  `OPERATION_REOPERATION_METHOD_EXTENTION_FIX` tinyint DEFAULT NULL,
  `OPERATION_REOPERATION_METHOD_OTHER` tinyint DEFAULT NULL,
  `INSTRUMENT_IMPLANT_MESA` tinyint DEFAULT NULL,
